# -*- coding: utf-8 -*-
"""
deploy_feishu_alert.py — Phase 1:飞书告警接线 (v1.1.0)
=====================================================
装 datasource/feishu_alert.py + 把 webhook 注入 HealthReporter。
前置:已部署 datasource 包 + datasource_v1 路由(Part A/B)。

配置(部署前或后,设环境变量):
  setx AIHF_FEISHU_WEBHOOK "https://open.feishu.cn/open-apis/bot/v2/hook/你的token"
  setx AIHF_FEISHU_SECRET  "你的签名密钥"   (启用签名校验时才需要)
  注意 setx 后要重开终端才生效;或当前会话用 set AIHF_FEISHU_WEBHOOK=...

用法:
    cd E:\\AI-tool\\Stock\\ai-hedge-fund
    poetry run python deploy_feishu_alert.py
"""
import base64, os, sys, datetime, traceback
_DEFAULT=r"E:\AI-tool\Stock\ai-hedge-fund"
ROOT = sys.argv[1] if len(sys.argv)>1 else (os.getcwd() if os.path.isdir(os.path.join(os.getcwd(),"src","tools")) else _DEFAULT)
TOOLS=os.path.join(ROOT,"src","tools")
PKG=os.path.join(TOOLS,"datasource")
if not os.path.isdir(PKG):
    print("[FATAL] 未找到 datasource 包,请先跑 deploy_datasource_phase1.py / _phase1b"); sys.exit(2)
print("ROOT =", ROOT, ("OK" if os.path.normpath(ROOT)==os.path.normpath(os.getcwd()) else "⚠️与CWD不同"))

FA_B64=""; OVR_B64=""
print("\n==== 1) 写入 feishu_alert.py ====")
p=os.path.join(PKG,"feishu_alert.py")
open(p,"w",encoding="utf-8",newline="\n").write(base64.b64decode(FA_B64).decode("utf-8"))
print("  写入 datasource/feishu_alert.py (%d bytes)"%os.path.getsize(p))

print("\n==== 2) 追加飞书接线 override ====")
api=os.path.join(TOOLS,"api_china.py")
ex=open(api,"r",encoding="utf-8",errors="replace").read()
if "marker:feishu_alert_v1" in ex:
    print("  已含,跳过(幂等)")
else:
    open(api,"a",encoding="utf-8",newline="\n").write(base64.b64decode(OVR_B64).decode("utf-8"))
    print("  追加完成")

print("\n==== 3) 验证 ====")
sys.path.insert(0,ROOT)
try:
    from src.tools.datasource import feishu_alert as fa
    has_url = bool(os.environ.get("AIHF_FEISHU_WEBHOOK"))
    print("AIHF_FEISHU_WEBHOOK 已配置:", has_url)
    print("AIHF_FEISHU_SECRET 已配置:", bool(os.environ.get("AIHF_FEISHU_SECRET")))
    from src.tools import api_china as cn
    wired = bool(getattr(cn, "_FEISHU_ALERT_INSTALLED", False))
    print("已注入 HealthReporter:", wired, "" if wired else "(未配 webhook 则静默,属正常)")
    if has_url:
        r = fa.diagnose()
        print("飞书返回: http=%s code=%s msg=%s" % (r.get("http"), r.get("code"), r.get("msg")))
        if r.get("ok"):
            print("发送测试告警: ✅ 成功(去飞书群看)")
        else:
            print("发送测试告警: ❌ 失败 —— 飞书拒收,按 code 排查:")
            print("  · 地址必须是【群自定义机器人】webhook,token 是 UUID 形如")
            print("    https://open.feishu.cn/open-apis/bot/v2/hook/1be45a07-ebe6-...")
            print("    若你填的是 cli_xxx(那是开放平台App ID,不是机器人webhook)→ 必失败")
            print("  · code=19021 sign 错 → AIHF_FEISHU_SECRET 必须是机器人【签名校验】密钥(非App Secret)")
            print("  · code~19024 关键词不匹配 → 机器人若设了自定义关键词,需包含「数据源告警」")
            print("  · 原始返回:", r.get("raw"))
    else:
        print("未配 webhook → 跳过发送测试。")
except Exception:
    print("[验证异常]\n"+traceback.format_exc())
print("\n==== 完成 ====  把输出贴回")
